   102→  /* Remove animations and transitions for users who prefer reduced motion */
   103→  @media (prefers-reduced-motion: reduce) {
   104→    *,
   105→    *::before,
   106→    *::after {
   107→      animation-duration: 0.01ms !important;
   108→      animation-iteration-count: 1 !important;
   109→      transition-duration: 0.01ms !important;
   110→      scroll-behavior: auto !important;
   111→    }
   112→  }
   113→}
   114→
   115→/* ==========================================================================
   116→   TOKENS LAYER
   117→   Design tokens as CSS custom properties on :root.
   118→
   119→   Token system:
   120→   - Spacing:    4px base unit, named --space-xs through --space-3xl
   121→   - Colors:     oklch color space for perceptual uniformity
   122→   - Typography: System font stack, fluid type scale with clamp()
   123→   - Shadows:    Three levels (sm, md, lg)
   124→   - Radii:      Three sizes (sm, md, lg)
   125→   - Transitions: Duration values for consistent animation timing
   126→
   127→   All component styles reference tokens -- no hardcoded values.
   128→   Token changes go through the mob with Steve Schoger's approval.
   129→   ========================================================================== */
   130→
   131→@layer tokens {
   132→  :root {
   133→    /* ---- Spacing Scale ----
   134→     * 4px base unit.
   135→     * Scale: 4, 8, 12, 16, 24, 32, 48, 64, 96
   136→     * Per TEAM_AGREEMENTS.md spacing scale definition.
   137→     */
   138→    --space-xs: 0.25rem;   /* 4px */
   139→    --space-sm: 0.5rem;    /* 8px */
   140→    --space-md: 0.75rem;   /* 12px */
   141→    --space-base: 1rem;    /* 16px */
   142→    --space-lg: 1.5rem;    /* 24px */
   143→    --space-xl: 2rem;      /* 32px */
   144→    --space-2xl: 3rem;     /* 48px */
   145→    --space-3xl: 4rem;     /* 64px */
   146→    --space-4xl: 6rem;     /* 96px */
   147→
   148→    /* ---- Color Palette ----
   149→     * oklch color space for perceptual uniformity.
   150→     * Most UI is grayscale; color is for emphasis and interaction.
   151→     *
   152→     * oklch(Lightness Chroma Hue)
   153→     * - Lightness: 0 (black) to 1 (white)
   154→     * - Chroma: 0 (gray) to ~0.4 (most saturated)
   155→     * - Hue: 0-360 degrees
   156→     */
   157→
   158→    /* Neutral grays -- zero chroma for true neutrals */
   159→    --color-gray-50:  oklch(0.985 0 0);
   160→    --color-gray-100: oklch(0.96 0 0);
   161→    --color-gray-200: oklch(0.9 0 0);
   162→    --color-gray-300: oklch(0.82 0 0);
   163→    --color-gray-400: oklch(0.7 0 0);
   164→    --color-gray-500: oklch(0.55 0 0);
   165→    --color-gray-600: oklch(0.44 0 0);
   166→    --color-gray-700: oklch(0.37 0 0);
   167→    --color-gray-800: oklch(0.27 0 0);
   168→    --color-gray-900: oklch(0.18 0 0);
   169→    --color-gray-950: oklch(0.12 0 0);
   170→
   171→    /* Primary -- blue for interactive elements
   172→     * Hue ~250 (blue), moderate chroma for a professional look */
   173→    --color-primary:       oklch(0.55 0.15 250);
   174→    --color-primary-light: oklch(0.70 0.12 250);
   175→    --color-primary-dark:  oklch(0.42 0.15 250);
   176→
   177→    /* Semantic colors */
   178→    --color-danger:  oklch(0.55 0.2 25);   /* Red-ish, hue ~25 */
   179→    --color-success: oklch(0.55 0.15 145);  /* Green-ish, hue ~145 */
   180→    --color-warning: oklch(0.7 0.15 80);    /* Amber-ish, hue ~80 */
   181→
   182→    /* Foreground / background semantic tokens */
   183→    --color-bg:        var(--color-gray-50);
   184→    --color-fg:        var(--color-gray-900);
   185→    --color-fg-muted:  var(--color-gray-500);
   186→    --color-border:    var(--color-gray-300);
   187→    --color-surface:   white;
   188→
   189→    /* ---- Typography ----
   190→     * System font stack -- no web font downloads, instant rendering.
   191→     * Fluid type scale using clamp() for smooth scaling between
   192→     * viewport sizes. Min at ~320px, max at ~1200px.
   193→     */
   194→    --font-family: system-ui, -apple-system, "Segoe UI", Roboto,
   195→      "Helvetica Neue", Arial, "Noto Sans", sans-serif,
   196→      "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji";
   197→
   198→    --font-family-mono: ui-monospace, "Cascadia Code", "Source Code Pro",
   199→      Menlo, Consolas, "DejaVu Sans Mono", monospace;
   200→
   201→    /* Fluid type scale
   202→     * clamp(min, preferred, max)
   203→     * Preferred uses viewport units for smooth scaling */
   204→    --font-size-xs:   clamp(0.75rem, 0.7rem + 0.25vw, 0.8125rem);   /* ~12-13px */
   205→    --font-size-sm:   clamp(0.8125rem, 0.775rem + 0.25vw, 0.875rem); /* ~13-14px */
   206→    --font-size-base: clamp(0.875rem, 0.825rem + 0.3vw, 1rem);       /* ~14-16px */
   207→    --font-size-md:   clamp(1rem, 0.925rem + 0.4vw, 1.125rem);       /* ~16-18px */
   208→    --font-size-lg:   clamp(1.125rem, 1rem + 0.5vw, 1.25rem);        /* ~18-20px */
   209→    --font-size-xl:   clamp(1.25rem, 1.1rem + 0.7vw, 1.5rem);        /* ~20-24px */
   210→    --font-size-2xl:  clamp(1.5rem, 1.3rem + 1vw, 1.875rem);         /* ~24-30px */
   211→    --font-size-3xl:  clamp(1.875rem, 1.6rem + 1.3vw, 2.25rem);      /* ~30-36px */
   212→
   213→    /* Line heights */
   214→    --leading-tight:  1.25;
   215→    --leading-normal: 1.5;
   216→    --leading-loose:  1.75;
   217→
   218→    /* Font weights */
   219→    --font-normal:    400;
   220→    --font-medium:    500;
   221→    --font-semibold:  600;
   222→    --font-bold:      700;
   223→
   224→    /* ---- Shadows ----
   225→     * Three levels. Shadows use oklch for consistency with the color system.
   226→     * Never combine shadows and borders on the same element (per team agreement).
   227→     */
   228→    --shadow-sm:  0 1px 2px 0 oklch(0.18 0 0 / 0.05);
   229→    --shadow-md:  0 4px 6px -1px oklch(0.18 0 0 / 0.08),
   230→                  0 2px 4px -2px oklch(0.18 0 0 / 0.05);
   231→    --shadow-lg:  0 10px 15px -3px oklch(0.18 0 0 / 0.08),
   232→                  0 4px 6px -4px oklch(0.18 0 0 / 0.03);
   233→
   234→    /* ---- Border Radius ---- */
   235→    --radius-sm:  0.25rem;  /* 4px */
   236→    --radius-md:  0.5rem;   /* 8px */
   237→    --radius-lg:  0.75rem;  /* 12px */
   238→
   239→    /* ---- Transition Durations ----
   240→     * Used within prefers-reduced-motion media queries only.
   241→     */
   242→    --transition-fast:   120ms;
   243→    --transition-normal: 200ms;
   244→
   245→    /* ---- Focus Ring ----
   246→     * Reusable focus ring properties for consistent :focus-visible styles.
   247→     * 3:1+ contrast against background (blue on white/light gray).
   248→     */
   249→    --focus-ring-color:  var(--color-primary);
   250→    --focus-ring-offset: 2px;
   251→    --focus-ring-width:  2px;
   252→  }
   253→}
   254→
   255→/* ==========================================================================
   256→   BASE LAYER
   257→   Element-level styles applied directly to HTML elements.
   258→   No classes -- this establishes the typographic and interactive baseline.
   259→   ========================================================================== */
   260→
   261→@layer base {
   262→  body {
   263→    font-family: var(--font-family);
   264→    font-size: var(--font-size-base);
   265→    font-weight: var(--font-normal);
   266→    line-height: var(--leading-normal);
   267→    color: var(--color-fg);
   268→    background-color: var(--color-bg);
   269→  }
   270→
   271→  /* Headings -- tighter line-height, bolder weight, type scale */
   272→  h1 {
   273→    font-size: var(--font-size-3xl);
   274→    font-weight: var(--font-bold);
   275→    line-height: var(--leading-tight);
   276→  }
   277→
   278→  h2 {
   279→    font-size: var(--font-size-2xl);
   280→    font-weight: var(--font-bold);
   281→    line-height: var(--leading-tight);
   282→  }
   283→
   284→  h3 {
   285→    font-size: var(--font-size-xl);
   286→    font-weight: var(--font-semibold);
   287→    line-height: var(--leading-tight);
   288→  }
   289→
   290→  h4 {
   291→    font-size: var(--font-size-lg);
   292→    font-weight: var(--font-semibold);
   293→    line-height: var(--leading-tight);
   294→  }
   295→
   296→  h5 {
   297→    font-size: var(--font-size-md);
   298→    font-weight: var(--font-medium);
   299→    line-height: var(--leading-tight);
   300→  }
   301→
   302→  h6 {
   303→    font-size: var(--font-size-base);
   304→    font-weight: var(--font-medium);
   305→    line-height: var(--leading-tight);
   306→  }
   307→
   308→  /* Links */
   309→  a {
   310→    color: var(--color-primary);
   311→    text-decoration: underline;
   312→    text-underline-offset: 0.15em;
   313→
   314→    &:hover {
   315→      color: var(--color-primary-dark);
   316→    }
   317→  }
   318→
   319→  /* Focus-visible styles for all interactive elements.
   320→   * Uses outline for keyboard focus, visible only on keyboard navigation.
   321→   * 3:1+ contrast ratio: blue ring on white/light gray background. */
   322→  :focus-visible {
   323→    outline: var(--focus-ring-width) solid var(--focus-ring-color);
   324→    outline-offset: var(--focus-ring-offset);
   325→  }
   326→
   327→  /* Buttons -- reset to a clean base, ready for component styles */
   328→  button,
   329→  [type="button"],
   330→  [type="submit"],
   331→  [type="reset"] {
   332→    display: inline-flex;
   333→    align-items: center;
   334→    justify-content: center;
   335→    gap: var(--space-sm);
   336→    padding-block: var(--space-sm);
   337→    padding-inline: var(--space-base);
   338→    font-size: var(--font-size-base);
   339→    font-weight: var(--font-medium);
   340→    line-height: var(--leading-tight);
   341→    border-radius: var(--radius-md);
   342→    background-color: var(--color-primary);
   343→    color: white;
   344→
   345→    &:hover {
   346→      background-color: var(--color-primary-dark);
   347→    }
   348→  }
   349→
   350→  @media (prefers-reduced-motion: no-preference) {
   351→    button,
   352→    [type="button"],
   353→    [type="submit"],
   354→    [type="reset"] {
   355→      transition: background-color var(--transition-fast) ease-in-out;
   356→    }
   357→  }
   358→
   359→  /* Form inputs */
   360→  input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
   361→  textarea,
   362→  select {
   363→    display: block;
   364→    inline-size: 100%;
   365→    padding-block: var(--space-sm);
   366→    padding-inline: var(--space-md);
   367→    font-size: var(--font-size-base);
   368→    line-height: var(--leading-normal);
   369→    color: var(--color-fg);
   370→    background-color: var(--color-surface);
   371→    border: 1px solid var(--color-border);
   372→    border-radius: var(--radius-md);
   373→
   374→    &::placeholder {
   375→      color: var(--color-fg-muted);
   376→    }
   377→  }
   378→
   379→  /* Labels */
   380→  label {
   381→    display: block;
   382→    font-size: var(--font-size-sm);
   383→    font-weight: var(--font-medium);
   384→    color: var(--color-fg);
   385→  }
   386→
   387→  /* Fieldset */
   388→  fieldset {
   389→    border: none;
   390→  }
   391→
   392→  /* Code */
   393→  code,
   394→  pre {
   395→    font-family: var(--font-family-mono);
   396→    font-size: var(--font-size-sm);
   397→  }
   398→}
   399→
   400→/* ==========================================================================
   401→   LAYOUT LAYER
   402→   Page-level layout using CSS Grid. Mobile-first, desktop breakpoint ~1024px.
   403→   Uses logical properties for RTL support.
   404→   ========================================================================== */
   405→
   406→@layer layout {
   407→  /* Page layout: header / main / footer with sticky footer */
   408→  .page-layout {
   409→    display: grid;
   410→    grid-template-rows: auto 1fr auto;
   411→    min-block-size: 100vh;
   412→  }
   413→
   414→  /* Constrained content container */
   415→  .container {
   416→    inline-size: 100%;
   417→    max-inline-size: 40rem; /* ~640px -- a todo list is narrow */
   418→    margin-inline: auto;
   419→    padding-inline: var(--space-base);
   420→  }
   421→
   422→  /* Wider container variant for pages that need more space */
   423→  .container--wide {
   424→    max-inline-size: 64rem; /* ~1024px */
   425→  }
   426→
   427→  /* Responsive adjustments */
   428→  @media (min-width: 1024px) {
   429→    .container {
   430→      padding-inline: var(--space-lg);
   431→    }
   432→  }
   433→
   434→  /* Container query setup -- components can respond to their container */
   435→  .component-container {
   436→    container-type: inline-size;
   437→  }
   438→}
   439→
   440→/* ==========================================================================
   441→   COMPONENTS LAYER
   442→   Component-specific styles are added here as features are built.
   443→   Each component should be self-contained and reference only design tokens.
   444→   ========================================================================== */
   445→
   446→@layer components {
   447→  /* Components will be added here as features are developed.
   448→   * Each feature's CSS goes in this layer.
   449→   * Example (future):
   450→   *   .todo-item { ... }
   451→   *   .auth-form { ... }
   452→   */
   453→}
   454→
   455→/* ==========================================================================
   456→   UTILITIES LAYER
   457→   Helper classes. These have the highest layer priority.
   458→   ========================================================================== */
   459→
   460→@layer utilities {
   461→  /* Visually hidden -- accessible to screen readers but not visible.
   462→   * Uses the clip technique for reliable hiding. */
   463→  .visually-hidden,
   464→  .sr-only {
   465→    position: absolute;
   466→    inline-size: 1px;
   467→    block-size: 1px;
   468→    padding: 0;
   469→    margin: -1px;
   470→    overflow: hidden;
   471→    clip-path: inset(50%);
   472→    white-space: nowrap;
   473→    border: 0;
   474→  }
   475→}
   476→

